INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'hostels', 'Hostels > NIT Srinagar has 8 hostels: Indus, Chenab, Mansar, Mansbal, Jhelum Extension, Jhelum, Tawi, and PG Hostel.');
