INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'mess', 'Mess > Advance: Rs 21,000 per semester mess advance (adjustable) + Rs 1,500 BHM Contribution.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'mess', 'Mess > Source: Chenab Mess menu.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'mess', 'Mess > Monday Breakfast: Poha + Aloo Bhujia + Lemon + Tea/Salt Tea OR Kashmiri Roti(2) + Butter + Tea.');
