INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'mess', 'Mess > Tuesday Dinner: Kadhi Pakoda + Mix Veg Sabji + Onion Salad + Roti + Rice + Mirchi + Kheer.');
