INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'mess', 'Mess > Notes: Kashmiri Roti is a daily breakfast option (unique to NIT Srinagar). Non-veg chicken served on Monday, Wednesday, and Friday dinners. Butter Chicken on Friday. Desserts: Kheer on Tuesday, Halwa on Thursday, Sewaiyan on Sunday.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'mess', 'Mess > Cuisine: North Indian and Kashmiri cuisine. Kashmiri Roti as a daily breakfast staple. Both veg and non-veg dinner options on Mon/Wed/Fri.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > Program: B.Tech Batch 2023, Even Semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > Part I components per semester: Admission fee Rs 1,000 + Library fee Rs 500 + IT System fee Rs 1,100 + T&P Charges Rs 500 + Transport facility Rs 500 + Medical facility Rs 300 + Examination fee Rs 1,200 + Gymkhana/Sport fee Rs 1,500 + Mediclaim Insurance Rs 270 + Hostel Seat Rent Rs 1,500 + Light and Water Rs 1,000 + Cable TV Rs 130 + Mess Establishment Rs 1,500. Subtotal: Rs 11,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > SC/ST/PwD students: Tuition fee Rs 0, total payable Rs 11,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > Family income less than Rs 1 lakh: Tuition fee Rs 0, total payable Rs 11,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > Family income Rs 1-5 lakh: Tuition fee Rs 20,833, total payable Rs 31,833 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > Family income above Rs 5 lakh: Tuition fee Rs 62,500, total payable Rs 73,500 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > Part II: BHM Contribution Rs 1,500 + Mess Advance (adjustable) Rs 21,000 = Part II Total Rs 22,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > 8th Semester additional charges: Transcript Fee Rs 1,500 + Convocation Reg Fee Rs 50 + Tuition Fee Rs 16,500. 8th Sem totals: SC/ST Rs 12,500, income <1L Rs 12,500, income 1-5L Rs 33,333, income >5L Rs 75,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fee_structure', 'Fee Structure > Foreign students: SAARC countries USD 2,000 per semester. Non-SAARC countries USD 4,000 per semester.');
