INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'fines', 'Fines > Rs 1,000 to Rs 5,000 for: Inappropriate behavior, Ragging, Smoking/Drinking on premises, Fights, and Damaging equipment.');
