INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'academics', 'Academics > NIT Srinagar has 8 B.Tech branches: Civil Engineering (2 sections), Mechanical Engineering, Chemical Engineering, Metallurgical & Materials Engineering, Electrical Engineering, Electronics & Communication Engineering, Computer Science Engineering, and Information Technology.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'academics', 'Academics > B.Tech 2nd Semester, Spring 2026 timetable. Classes run Monday to Friday, 9 AM to 5:20 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'academics', 'Academics > Common 2nd semester subjects: Engineering Physics, Mathematics II, Advanced English and Communication Skills, Environmental Studies, Elements of Mechanical Engineering, Engineering Mechanics, Workshop Practice, Engineering Drawing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Srinagar', 'academics', 'Academics > Branch-specific subjects for EE/ECE/CSE/IT: Engineering Chemistry, Computer Programming, Basic Electrical Engineering.');
